import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";

interface ReactionCounts {
  likes: number;
  dislikes: number;
}

export function useStoryReactions(restaurantId: string | undefined) {
  const { user } = useAuth();
  const queryClient = useQueryClient();

  const { data: counts = { likes: 0, dislikes: 0 } } = useQuery<ReactionCounts>({
    queryKey: ["story-reactions-counts", restaurantId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("story_reactions" as any)
        .select("reaction_type")
        .eq("restaurant_id", restaurantId!);
      if (error) throw error;
      const items = data as any[];
      return {
        likes: items.filter((r) => r.reaction_type === "like").length,
        dislikes: items.filter((r) => r.reaction_type === "dislike").length,
      };
    },
    enabled: !!restaurantId,
  });

  const { data: userReaction } = useQuery<string | null>({
    queryKey: ["story-reaction-user", restaurantId, user?.id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("story_reactions" as any)
        .select("reaction_type")
        .eq("restaurant_id", restaurantId!)
        .eq("user_id", user!.id)
        .maybeSingle();
      if (error) throw error;
      return (data as any)?.reaction_type || null;
    },
    enabled: !!restaurantId && !!user,
  });

  const toggleReaction = useMutation({
    mutationFn: async (type: "like" | "dislike") => {
      if (!user || !restaurantId) throw new Error("Not authenticated");

      if (userReaction === type) {
        // Remove reaction
        await supabase
          .from("story_reactions" as any)
          .delete()
          .eq("restaurant_id", restaurantId)
          .eq("user_id", user.id);
      } else if (userReaction) {
        // Change reaction
        await supabase
          .from("story_reactions" as any)
          .update({ reaction_type: type } as any)
          .eq("restaurant_id", restaurantId)
          .eq("user_id", user.id);
      } else {
        // New reaction
        await supabase
          .from("story_reactions" as any)
          .insert({ restaurant_id: restaurantId, user_id: user.id, reaction_type: type } as any);
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["story-reactions-counts", restaurantId] });
      queryClient.invalidateQueries({ queryKey: ["story-reaction-user", restaurantId, user?.id] });
    },
  });

  return { counts, userReaction: userReaction ?? null, toggleReaction };
}
