import { useState, useEffect, useRef, useCallback, useMemo } from "react";
import { useTranslation } from "react-i18next";
import { Languages, Loader2, RotateCcw } from "lucide-react";
import { Button } from "@/components/ui/button";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

/** Detect if text is predominantly Chinese */
function isChineseText(text: string): boolean {
  const chineseChars = text.match(/[\u4e00-\u9fff\u3400-\u4dbf]/g);
  const totalChars = text.replace(/\s/g, "").length;
  if (!chineseChars || totalChars === 0) return false;
  return chineseChars.length / totalChars > 0.6;
}

const translationCache = new Map<string, string>();
const SECTION_SEP = "---SECTION---";

interface IChingSectionProps {
  /** The I Ching text (may be in any language, will auto-translate to Chinese) */
  text: string;
  /** Override display text (from parent's unified translation) */
  translatedText?: string | null;
  className?: string;
  /** If true, hide the label header */
  hideLabel?: boolean;
}

/**
 * I Ching display component.
 * Always displays in Chinese. If the source text is not Chinese,
 * it auto-translates to Chinese on mount. Users can translate to
 * their language via the parent's translate button.
 */
const IChingSection = ({ text, translatedText, className, hideLabel }: IChingSectionProps) => {
  const { t, i18n } = useTranslation();
  const [chineseText, setChineseText] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const alreadyChinese = useRef(isChineseText(text));
  const autoTranslated = useRef(false);

  // Auto-translate to Chinese on mount if text is not predominantly Chinese
  useEffect(() => {
    if (alreadyChinese.current) {
      setChineseText(text);
      return;
    }
    if (autoTranslated.current) return;
    autoTranslated.current = true;

    const cacheKey = `iching_zh_${text.substring(0, 100)}`;
    const cached = translationCache.get(cacheKey);
    if (cached) {
      setChineseText(cached);
      return;
    }

    setIsLoading(true);
    supabase.functions
      .invoke("translate-content", { body: { text, targetLang: "zh" } })
      .then(({ data, error }) => {
        if (!error && data?.translatedText) {
          translationCache.set(cacheKey, data.translatedText);
          setChineseText(data.translatedText);
        } else {
          setChineseText(text);
        }
      })
      .catch(() => setChineseText(text))
      .finally(() => setIsLoading(false));
  }, [text]);

  // Display priority: parent's translation (user clicked translate) > auto-translated Chinese > original
  const displayText = translatedText || chineseText || text;

  const label = t("iching.label", "I Ching Interpretation");

  return (
    <div className={className}>
      {!hideLabel && (
        <p className="text-xs font-medium text-muted-foreground mb-2 flex items-center gap-1.5">
          <span>☰</span>
          {label}
        </p>
      )}
      {isLoading && !chineseText ? (
        <p className="text-sm text-muted-foreground italic flex items-center gap-2">
          <Loader2 className="h-3 w-3 animate-spin" />
          {t("translate.translating", "翻译中...")}
        </p>
      ) : (
        <p className="whitespace-pre-line text-sm leading-[1.8] text-foreground/80 italic">
          {displayText}
        </p>
      )}
    </div>
  );
};

export default IChingSection;

/** Exported helper: unified translation for building story + I Ching (manual only) */
export function useStoryTranslation(buildingNarrative: string, iChingText: string) {
  const { i18n } = useTranslation();
  const [translatedNarrative, setTranslatedNarrative] = useState<string | null>(null);
  const [translatedIChing, setTranslatedIChing] = useState<string | null>(null);
  const [isTranslating, setIsTranslating] = useState(false);
  const [showTranslation, setShowTranslation] = useState(false);

  /** Translate both narrative + I Ching */
  const translateStory = useCallback(async (targetLang: string): Promise<boolean> => {
    // Toggle back to original
    if (showTranslation) {
      setShowTranslation(false);
      return true;
    }

    const parts: string[] = [];
    if (buildingNarrative) parts.push(buildingNarrative);
    if (iChingText) parts.push(iChingText);
    if (parts.length === 0) return false;

    const combined = parts.join(`\n${SECTION_SEP}\n`);
    const cacheKey = `story_${combined.substring(0, 100)}_${targetLang}`;
    const cached = translationCache.get(cacheKey);

    const applySplit = (raw: string) => {
      const splitParts = raw.split(SECTION_SEP);
      if (buildingNarrative && iChingText) {
        setTranslatedNarrative(splitParts[0]?.trim() || null);
        setTranslatedIChing(splitParts[1]?.trim() || null);
      } else if (buildingNarrative) {
        setTranslatedNarrative(splitParts[0]?.trim() || null);
      } else {
        setTranslatedIChing(splitParts[0]?.trim() || null);
      }
    };

    if (cached) {
      applySplit(cached);
      setShowTranslation(true);
      return true;
    }

    setIsTranslating(true);
    try {
      const { data, error } = await supabase.functions.invoke("translate-content", {
        body: { text: combined, targetLang },
      });
      if (!error && data?.translatedText) {
        translationCache.set(cacheKey, data.translatedText);
        applySplit(data.translatedText);
        setShowTranslation(true);
        return true;
      }
    } catch {
      // silently fail
    } finally {
      setIsTranslating(false);
    }
    return false;
  }, [buildingNarrative, iChingText, showTranslation]);

  return {
    narrativeDisplay: showTranslation ? translatedNarrative : null,
    iChingDisplay: showTranslation ? translatedIChing : null,
    translateStory,
    isTranslating,
    showTranslation,
  };
}
